#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long total = 2LL * N;
        long long large = 0, ans = 0;
        for(long long i=0;i<total;i++){
            long long x; scanf("%lld", &x);
            if(x > N) large++;
            else ans += large;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

